#include <stdio.h>

int reverseNum(int n) {
    int res = 0;
    while (n > 0) {
        int d = n % 10;
        res = res * 10 + d;
        n /= 10;
    }
    return res;
}

int main() {
    int t;
    if (scanf("%d", &t) != 1) return 0;
    while (t--) {
        int n;
        scanf("%d", &n);
        printf("%d\n", reverseNum(n));
    }
    return 0;
}

