const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const t = parseInt(input[idx++], 10);
let results = [];
function reverseNum(n) {
    let res = 0;
    while (n > 0) {
        res = res * 10 + (n % 10);
        n = Math.floor(n / 10);
    }
    return res;
}
for (let i = 0; i < t; i++) {
    const n = parseInt(input[idx++], 10);
    results.push(String(reverseNum(n)));
}
console.log(results.join('\n'));

